import React from 'react';

const Navbar = () => {
  const links = ["HISTORIA", "PRESENTACIONES", "INICIO", "EMPRESAS", "CONTACTO"];

  return (
    <nav className="w-full flex justify-center items-center gap-6 py-2 bg-white border-b text-gray-800">
      {links.map((link, index) => (
        <span
          key={index}
          className={`text-sm tracking-widest font-light ${
            link === "INICIO" ? "font-semibold" : ""
          }`}
        >
          {link}
        </span>
      ))}
    </nav>
  );
};

export default Navbar;
